local Players = game:GetService("Players") local RunService = game:GetService("RunService") local CoreGui = game:GetService("CoreGui") -- CÀI ĐẶT MẶC ĐỊNH local Settings = { Box = true, Tracer = true, Name = true, Health = true } -- 1. TẠO GUI CHÍNH local ScreenGui = Instance.new("ScreenGui") ScreenGui.Name = "EspUltraMenu" ScreenGui.Parent = CoreGui ScreenGui.ResetOnSpawn = false -- 2. NÚT BẤM MỞ MENU (TOGGLE BUTTON) - Dành cho Mobile/PC local OpenBtn = Instance.new("TextButton") OpenBtn.Size = UDim2.new(0, 100, 0, 40) OpenBtn.Position = UDim2.new(0, 10, 0.5, -20) -- Nằm bên trái màn hình OpenBtn.Text = "OPEN MENU" OpenBtn.BackgroundColor3 = Color3.fromRGB(0, 255, 255) OpenBtn.TextColor3 = Color3.new(0, 0, 0) OpenBtn.Font = Enum.Font.SourceSansBold OpenBtn.Parent = ScreenGui -- Bo góc cho nút bấm local UICornerBtn = Instance.new("UICorner") UICornerBtn.CornerRadius = UDim.new(0, 8) UICornerBtn.Parent = OpenBtn -- 3. KHUNG MENU ĐIỀU KHIỂN local MainFrame = Instance.new("Frame") MainFrame.Size = UDim2.new(0, 220, 0, 280) MainFrame.Position = UDim2.new(0.5, -110, 0.5, -140) MainFrame.BackgroundColor3 = Color3.fromRGB(20, 20, 20) MainFrame.Visible = false -- Mặc định ẩn MainFrame.Active = true MainFrame.Draggable = true -- Có thể kéo thả MainFrame.Parent = ScreenGui local UICornerFrame = Instance.new("UICorner") UICornerFrame.Parent = MainFrame local Title = Instance.new("TextLabel") Title.Size = UDim2.new(1, 0, 0, 45) Title.Text = "ESP CONTROL" Title.TextColor3 = Color3.fromRGB(0, 255, 255) Title.BackgroundColor3 = Color3.fromRGB(35, 35, 35) Title.Parent = MainFrame -- Hàm xử lý ẩn/hiện Menu OpenBtn.MouseButton1Click:Connect(function() MainFrame.Visible = not MainFrame.Visible OpenBtn.Text = MainFrame.Visible and "CLOSE" or "OPEN MENU" OpenBtn.BackgroundColor3 = MainFrame.Visible and Color3.fromRGB(255, 50, 50) or Color3.fromRGB(0, 255, 255) end) -- 4. TẠO CÁC NÚT CHỨC NĂNG TRONG MENU local function CreateToggle(text, pos, settingKey) local Btn = Instance.new("TextButton") Btn.Size = UDim2.new(0.9, 0, 0, 40) Btn.Position = UDim2.new(0.05, 0, 0, pos) Btn.Text = text .. ": ON" Btn.BackgroundColor3 = Color3.fromRGB(0, 180, 0) Btn.TextColor3 = Color3.new(1, 1, 1) Btn.Parent = MainFrame local Corner = Instance.new("UICorner") Corner.CornerRadius = UDim.new(0, 6) Corner.Parent = Btn Btn.MouseButton1Click:Connect(function() Settings[settingKey] = not Settings[settingKey] Btn.Text = text .. (Settings[settingKey] and ": ON" or ": OFF") Btn.BackgroundColor3 = Settings[settingKey] and Color3.fromRGB(0, 180, 0) or Color3.fromRGB(180, 0, 0) end) end CreateToggle("Box ESP", 60, "Box") CreateToggle("Tracer (Line)", 110, "Tracer") CreateToggle("Name & Distance", 160, "Name") CreateToggle("Health Bar", 210, "Health") -- 5. LOGIC VẼ ESP (Dùng Drawing API) local function CreateEsp(player) local Box = Drawing.new("Square") local Tracer = Drawing.new("Line") local Info = Drawing.new("Text") local HealthBar = Drawing.new("Line") local function Update() local connection connection = RunService.RenderStepped:Connect(function() if player.Character and player.Character:FindFirstChild("HumanoidRootPart") and player ~= Players.LocalPlayer then local Root = player.Character.HumanoidRootPart local Hum = player.Character:FindFirstChild("Humanoid") local Pos, OnScreen = workspace.CurrentCamera:WorldToViewportPoint(Root.Position) if OnScreen and Hum and Hum.Health > 0 then local Size = (workspace.CurrentCamera.ViewportSize.Y / Pos.Z) * 2 local w, h = Size, Size * 1.5 local x, y = Pos.X - w/2, Pos.Y - h/2 -- Cập nhật Box Box.Visible = Settings.Box Box.Size = Vector2.new(w, h); Box.Position = Vector2.new(x, y); Box.Color = Color3.fromRGB(0, 255, 255) -- Cập nhật Tracer Tracer.Visible = Settings.Tracer Tracer.From = Vector2.new(workspace.CurrentCamera.ViewportSize.X/2, workspace.CurrentCamera.ViewportSize.Y) Tracer.To = Vector2.new(Pos.X, Pos.Y + h/2); Tracer.Color = Color3.new(1,1,1) -- Cập nhật Info Info.Visible = Settings.Name local Dist = math.floor((Players.LocalPlayer.Character.HumanoidRootPart.Position - Root.Position).Magnitude) Info.Text = player.Name .. " [" .. Dist .. "m]"; Info.Position = Vector2.new(Pos.X, y - 20); Info.Center = true; Info.Outline = true -- Cập nhật Health HealthBar.Visible = Settings.Health HealthBar.From = Vector2.new(x - 6, y + h) HealthBar.To = Vector2.new(x - 6, y + h - (h * (Hum.Health / Hum.MaxHealth))) HealthBar.Color = Color3.fromHSV(Hum.Health/100 * 0.3, 1, 1); HealthBar.Thickness = 2 else Box.Visible = false; Tracer.Visible = false; Info.Visible = false; HealthBar.Visible = false end else Box.Visible = false; Tracer.Visible = false; Info.Visible = false; HealthBar.Visible = false if not player.Parent then Box:Remove(); Tracer:Remove(); Info:Remove(); HealthBar:Remove(); connection:Disconnect() end end end) end coroutine.wrap(Update)() end for _, p in pairs(Players:GetPlayers()) do CreateEsp(p) end Players.PlayerAdded:Connect(CreateEsp) 
